import math


def get_angle(a, b):
    return math.atan2(a[1] * b[0] - a[0] * b[1], a[0] * b[0] + a[1] * b[1])


n = int(input())
v = [list(map(int, input().split())) for _ in range(n)]
v.sort(key=lambda x: (x[0], x[1]))

min_angle = math.pi
a, b = 0, 0
for i in range(n):
    for j in range(i + 1, n):
        angle = get_angle(v[i], v[j])
        if angle < min_angle:
            min_angle = angle
            a, b = i + 1, j + 1

print(a, b)
